mapper.select:
	SELECT *
	FROM(	
		SELECT
			 MSG_NM AS msgNm
			,MSG_NM_SUB AS msgNmSub
			,MSG_VERSION AS msgVersion
			,MSG_DSCD AS msgDscd
			,REG_MAN_ID AS regManId
			,REG_DTTM AS regDttm
			,MSG_DATA_VAL AS msgDataVal
			,MSG_DESC AS msgDesc
			,EXTRNL_BIZ_NM AS extrnlBizNm
			,DTO_NM AS dtoNm
			,MSG_LAYOUT_ID AS msgLayoutId
			,APP_TYPE_CD AS appTypeCd
			,TRX_CD AS trxCd
			,APP_NM AS appNm
			,LV_1_CD AS lv1Cd
			,LV_2_CD AS lv2Cd
			,LV_3_CD AS lv3Cd
			,LV_4_CD AS lv4Cd
			,LV_5_CD AS lv5Cd
			,TRX_DSCD AS trxDscd
			,BIT_MAP_CRTN_YN AS bitMapCrtnYn
			,JOB_ID AS jobId
			,CHL_DSCD AS chlDscd
			,ISO8583_DATA_TYPE_CD AS iso8583DataTypeCd
			,CRTN_SEQ AS crtnSeq
			,RSRV_FLD_VAL1 AS rsrvFldVal1
			,RSRV_FLD_VAL2 AS rsrvFldVal2
			,RSRV_FLD_VAL3 AS rsrvFldVal3
			,BIT_MAP_TYPE_CD AS bitMapTypeCd
			,WORK_STATUS_CD AS workStatusCd
			,CUST_API_YN AS custApiYn
			,MSG_RVS_NO AS msgRvsNo
			,@rownum := @rownum + 1 AS rn
			
		FROM TBMSGLAYOUTBS
		WHERE 1=1
	
		AND MSG_NM like = #{msgNm, jdbcType = VARCHAR}
 	
	
		AND MSG_VERSION = #{msgVersion, jdbcType = NUMERIC}
 	
	
		AND MSG_DSCD = #{msgDscd, jdbcType = VARCHAR}
 	
	
		AND REG_MAN_ID = #{regManId, jdbcType = VARCHAR}
 	
	
		AND REG_DTTM = #{regDttm, jdbcType = VARCHAR}
 	
	
		AND MSG_DATA_VAL = #{msgDataVal, jdbcType = VARCHAR}
 	
	
		AND MSG_DESC = #{msgDesc, jdbcType = VARCHAR}
 	
	
		AND EXTRNL_BIZ_NM = #{extrnlBizNm, jdbcType = VARCHAR}
 	
	
		AND DTO_NM = #{dtoNm, jdbcType = VARCHAR}
 	
	
		AND MSG_LAYOUT_ID = #{msgLayoutId, jdbcType = VARCHAR}
 	
	
		AND APP_TYPE_CD = #{appTypeCd, jdbcType = VARCHAR}
 	
	
		AND TRX_CD = #{trxCd, jdbcType = VARCHAR}
 	
	
		AND APP_NM = #{appNm, jdbcType = VARCHAR}
 	
	
		AND LV_1_CD = #{lv1Cd, jdbcType = VARCHAR}
 	
	
		AND LV_2_CD = #{lv2Cd, jdbcType = VARCHAR}
 	
	
		AND LV_3_CD = #{lv3Cd, jdbcType = VARCHAR}
 	
	
		AND LV_4_CD = #{lv4Cd, jdbcType = VARCHAR}
 	
	
		AND LV_5_CD = #{lv5Cd, jdbcType = VARCHAR}
 	
	
		AND TRX_DSCD = #{trxDscd, jdbcType = VARCHAR}
 	
	
		AND BIT_MAP_CRTN_YN = #{bitMapCrtnYn, jdbcType = VARCHAR}
 	
	
		AND JOB_ID = #{jobId, jdbcType = VARCHAR}
 	
 	
		AND CHL_DSCD = #{chlDscd, jdbcType = VARCHAR}
 	
 	
		AND ISO8583_DATA_TYPE_CD = #{iso8583DataTypeCd, jdbcType = VARCHAR}
 	
 	
		AND CRTN_SEQ like CONCAT('%',#{crtnSeq, jdbcType = NUMERIC},'%')
 	
	
		AND RSRV_FLD_VAL1 like CONCAT('%',#{rsrvFldVal1, jdbcType = VARCHAR},'%')
 	
	
		AND RSRV_FLD_VAL2 like CONCAT('%',#{rsrvFldVal2, jdbcType = VARCHAR},'%')
 	
	
		AND RSRV_FLD_VAL3 like CONCAT('%',#{rsrvFldVal3, jdbcType = VARCHAR},'%')
 	
 		
		AND BIT_MAP_TYPE_CD like CONCAT('%',#{bitMapTypeCd, jdbcType = VARCHAR},'%')
 	
 	
		AND WORK_STATUS_CD like CONCAT('%',#{workStatusCd, jdbcType = VARCHAR},'%')
 	
 	
		AND CUST_API_YN like CONCAT('%',#{custApiYn, jdbcType = VARCHAR},'%')
 	
 	
		AND MSG_RVS_NO like CONCAT('%',#{msgRvsNo, jdbcType = NUMERIC},'%')
 	
 	order by REG_DTTM desc
	) p, (SELECT @rownum := 0) r
		WHERE p.rn > ((#{pageNumber , jdbcType=NUMERIC}-1) * #{pageSize , jdbcType=NUMERIC}) 
	    AND p.rn <= ((#{pageNumber , jdbcType=NUMERIC} * #{pageSize, jdbcType=NUMERIC}))

